       if (line.startsWith("u ")) {
         const parts = line.split(" ");
-        // Path is at index 10 (the 11th field)
-        const filePath = parts[10];
+        // Path starts at index 10 and may contain spaces
+        const filePath = parts.slice(10).join(" ");
         if (filePath) {
